import sailpoint.connector.JDBCConnector;
  import java.util.List;
  import sailpoint.tools.Util;
  import java.util.Map;
  import sailpoint.object.Schema;
  import sailpoint.object.AttributeDefinition;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;

  String delimiter = ",";
  Custom customObj=context.getObject(Custom.class,"Ascension-custom-generalConfiguration");
  if(customObj!=null){
    String appName=application.getName();
    Map delimiterMap=customObj.get("DelimiterforBuildMap");
    if( Util.isNotNullOrEmpty(delimiterMap.get(appName)) ){
      delimiter=delimiterMap.get(appName);
    }
  }

  List attValueList = new ArrayList();
  List valueList=new ArrayList();
 Map map = JDBCConnector.buildMapFromResultSet(result,schema);
  List allAttributes=schema.getAttributes();
  for(AttributeDefinition attr: allAttributes){
    if(attr.isMultiValued()){
      String value=map.get(attr.getName());
      if(Util.isNotNullOrEmpty(value) && value.contains(delimiter)){
        valueList=Arrays.asList(value.split(delimiter));
        attValueList = new ArrayList();
        for(String attValue : valueList){
          if(Util.isNotNullOrEmpty(attValue)){
            attValueList.add(attValue.trim());
          }
        }
        map.put(attr.getName(),attValueList);
      }
    }
  }
  return map;
